            double delta = std::abs(currentValue - lastValue);
            shouldRecompute = delta >= diffThreshold;
        }

        // Update last processed value only if we're recomputing
        if (shouldRecompute) {
            lastProcessed.value(currentValue);
        }

        return shouldRecompute;
    });

    // 5. Update sensor with first value
    sensor.value(firstUpdate);

    // 6. Record recompute count after first update
    int countAfterFirst = recomputeCount;

    // 7. Update sensor with second value
    sensor.value(secondUpdate);

    // 8. Record recompute count after second update
    int countAfterSecond = recomputeCount;

    // 9. Get final status
    std::string status;
    if (countAfterSecond > countAfterFirst) {
        status = "Recomputation triggered successfully";
    } else {
        status = "No recomputation occurred";
    }

    // 10. Return final status and counts
    return std::make_tuple(status, countAfterFirst, countAfterSecond);
}

