struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // 1. Create NamedObserverNode instances
    auto source = std::make_shared<NamedObserverNode>("source");
    auto direct = std::make_shared<NamedObserverNode>("direct");
    auto transitive = std::make_shared<NamedObserverNode>("transitive");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes (already done in constructors, but we'll ensure they're added)
    graph.addNode(source.get());
    graph.addNode(direct.get());
    graph.addNode(transitive.get());

    // 4. Set up direct observer relationship
    source->addOneObserver(direct.get());

    // 5. Set up transitive observer relationship
    direct->addOneObserver(transitive.get());

    // 6. Create NodeSet to store collected observers
    reaction::NodeSet collectedObservers;

    // 7. Collect observers from source node
    graph.collectObservers(*source, collectedObservers);

    // 8. Check if direct observer is in collected set
    bool containsDirect = collectedObservers.contains(direct.get());

    // 9. Check if transitive observer is in collected set
    bool containsTransitive = collectedObservers.contains(transitive.get());

    // 10. Return collection summary
    return ObserverCollectionSummary{
        .totalObservers = collectedObservers.size(),
        .containsDirectObserver = containsDirect,
        .containsTransitiveObserver = containsTransitive
    };
}

}  // namespace test_reaction

